from typing import Any, Literal

ExpansionStatus = Literal["implemented", "ready_to_wire", "requires_customer_infra"]


def _module(module_id: str, name: str, owner: str, status: ExpansionStatus, purpose: str, apis: list[str], workflow: list[str], evidence: list[str], gates: list[str]) -> dict[str, Any]:
    return {"id": module_id, "name": name, "owner": owner, "status": status, "purpose": purpose, "api_surface": apis, "workflow": workflow, "evidence": evidence, "readiness_gates": gates}


