def build_production_expansion_model() -> dict[str, Any]:
    implemented = len([item for item in PRODUCTION_EXPANSION_MODULES if item["status"] == "implemented"])
    ready = len([item for item in PRODUCTION_EXPANSION_MODULES if item["status"] == "ready_to_wire"])
    external = len([item for item in PRODUCTION_EXPANSION_MODULES if item["status"] == "requires_customer_infra"])
    return {"summary": {"modules": len(PRODUCTION_EXPANSION_MODULES), "implemented": implemented, "ready_to_wire": ready, "requires_customer_infra": external, "production_score": round(((implemented + ready * 0.7) / len(PRODUCTION_EXPANSION_MODULES)) * 100)}, "modules": PRODUCTION_EXPANSION_MODULES}
